"use client";
import { useEffect, useState, Suspense } from "react";
import { useSession } from "next-auth/react";
import { useSearchParams, useRouter } from "next/navigation";
import { Heart, MapPin, Eye, ArrowRight, Home, TrendingUp, Bed, Bath, Move } from "lucide-react";

function PropertiesContent() {
  const { data: session } = useSession();
  const router = useRouter();
  const searchParams = useSearchParams();
  
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [cityWiseData, setCityWiseData] = useState({ bilaspur: [], raipur: [], others: [] });

  const search = searchParams.get("search") || "";
  const district = searchParams.get("district") || "";
  const category = searchParams.get("category") || "All";

  // ... (Data Fetching Logic Same as before) ...
  const organizeByCity = (props) => {
    const bilaspur = [];
    const raipur = [];
    const others = [];
    props.forEach(prop => {
      const city = prop.district?.toLowerCase() || "";
      if (city.includes("bilaspur")) bilaspur.push(prop);
      else if (city.includes("raipur")) raipur.push(prop);
      else others.push(prop);
    });
    return { bilaspur: bilaspur.slice(0, 10), raipur: raipur.slice(0, 10), others: others };
  };

  useEffect(() => {
    const fetchProperties = async () => {
      setLoading(true);
      try {
        const params = new URLSearchParams();
        if (search) params.set("search", search);
        if (district) params.set("district", district);
        if (category && category !== "All") params.set("category", category);
        
        const res = await fetch(`/api/properties?${params.toString()}`);
        if (!res.ok) throw new Error("API Response failed");
        const data = await res.json();
        const allProps = data.properties || data;
        setProperties(allProps);
        
        if (category && category !== "All") setCityWiseData(organizeByCity(allProps));
        else setCityWiseData({ bilaspur: [], raipur: [], others: allProps });
      } catch (err) { console.error(err); } finally { setLoading(false); }
    };
    fetchProperties();
  }, [search, district, category, searchParams]);

  const handleLike = async (e, propertyId) => {
    e.stopPropagation();
    if (!session) return alert("Pehle Login karo bhai!");
    try {
      const res = await fetch(`/api/properties/${propertyId}/like`, { method: "POST" });
      const data = await res.json();
      if (res.ok) {
        setProperties(properties.map(p => p._id === propertyId ? { ...p, likes: data.likes } : p));
      }
    } catch (err) { console.log(err); }
  };

  if (loading) return (
    <div className="h-screen flex items-center justify-center bg-[#FDFDFD]">
      <div className="flex flex-col items-center gap-4">
        <div className="w-16 h-16 border-[6px] border-black border-t-transparent rounded-full animate-spin"></div>
      </div>
    </div>
  );

  // 🔥🔥🔥 THE GAND PHAD CARD 🔥🔥🔥
  const PropertyCard = ({ item }) => {
    const isLiked = item.likes?.includes(session?.user?.email);
    
    return (
      <div 
        onClick={() => router.push(`/properties/${item._id}`)} 
        className="group relative bg-white rounded-[2.5rem] border border-gray-200 overflow-hidden cursor-pointer transition-all duration-500 hover:shadow-2xl hover:shadow-blue-900/10 hover:-translate-y-2"
      >
        {/* IMAGE SECTION */}
        <div className="relative h-72 w-full overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent z-10 opacity-60"></div>
          <img 
            src={item.images[0] || "/no-image.png"} 
            alt={item.title} 
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 ease-in-out" 
          />
          
          {/* Top Badges */}
          <div className="absolute top-5 left-5 z-20 flex gap-2">
            <span className="bg-white/95 backdrop-blur-md text-black px-4 py-1.5 rounded-full text-[11px] font-black uppercase tracking-widest shadow-md">
              {item.cat || 'Featured'}
            </span>
          </div>

          {/* Like Button */}
          <button 
            onClick={(e) => handleLike(e, item._id)}
            className="absolute top-5 right-5 z-20 p-3 bg-white/30 backdrop-blur-md border border-white/40 rounded-full hover:bg-white transition-all duration-300 group-hover:scale-110"
          >
            <Heart size={20} className={isLiked ? "fill-red-500 text-red-500" : "text-white"} />
          </button>

          {/* Price Tag Overlay (Image ke upar hi dikha diya modern look ke liye) */}
          <div className="absolute bottom-5 left-5 z-20">
             <p className="text-white/80 text-[10px] font-bold uppercase tracking-widest mb-1">Asking Price</p>
             <p className="text-white text-3xl font-[1000] tracking-tight drop-shadow-md">
               ₹{item.price.toLocaleString('en-IN')}
             </p>
          </div>
        </div>

        {/* CONTENT SECTION */}
        <div className="p-7">
          {/* Title & Location */}
          <div className="mb-6">
            <h2 className="text-2xl font-[900] text-gray-900 leading-tight mb-2 group-hover:text-blue-600 transition-colors line-clamp-1">
              {item.title}
            </h2>
            <p className="flex items-center gap-2 text-gray-600 font-bold text-sm">
              <MapPin size={16} className="text-red-500" /> 
              {item.district}
            </p>
          </div>

          {/* Quick Stats Grid */}
          <div className="grid grid-cols-3 gap-2 mb-6">
            <div className="bg-gray-50 rounded-2xl p-3 flex flex-col items-center justify-center border border-gray-100">
               <Bed size={18} className="text-gray-900 mb-1"/>
               <span className="text-xs font-black text-gray-700">{item.details?.beds || 0} Bed</span>
            </div>
            <div className="bg-gray-50 rounded-2xl p-3 flex flex-col items-center justify-center border border-gray-100">
               <Bath size={18} className="text-gray-900 mb-1"/>
               <span className="text-xs font-black text-gray-700">{item.details?.baths || 0} Bath</span>
            </div>
            <div className="bg-gray-50 rounded-2xl p-3 flex flex-col items-center justify-center border border-gray-100">
               <Move size={18} className="text-gray-900 mb-1"/>
               <span className="text-xs font-black text-gray-700">{item.details?.area || 0} <span className="text-[9px]">sqft</span></span>
            </div>
          </div>

          {/* Footer: Views & Action */}
          <div className="flex justify-between items-center border-t border-gray-100 pt-5">
            <div className="flex gap-4">
              <span className="flex items-center gap-1.5 text-xs font-bold text-gray-500">
                <Eye size={16} className="text-gray-400" /> {item.views || 0}
              </span>
              <span className="flex items-center gap-1.5 text-xs font-bold text-gray-500">
                <Heart size={16} className="text-gray-400" /> {item.likes?.length || 0}
              </span>
            </div>

            <button className="bg-black text-white p-3 rounded-full group-hover:bg-blue-600 transition-colors duration-300">
               <ArrowRight size={20} />
            </button>
          </div>
        </div>
      </div>
    );
  };

  // --- SECTIONS ---
  const SectionHeader = ({ title }) => (
    <div className="flex items-end gap-4 mb-8 px-2">
       <h2 className="text-3xl md:text-4xl font-[900] text-gray-900 tracking-tighter uppercase">{title}</h2>
       <div className="h-[2px] flex-1 bg-gray-100 mb-2"></div>
    </div>
  );

  const renderContent = () => {
    if (!category || category === "All") {
      return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {properties.map(p => <PropertyCard key={p._id} item={p} />)}
        </div>
      );
    }
    const catName = category === "Room" ? "Rooms" : category === "PG" ? "PGs" : category === "House" ? "Houses" : "Plots";
    
    return (
      <div className="space-y-16">
        {cityWiseData.bilaspur.length > 0 && (
          <div><SectionHeader title={`${catName} in Bilaspur`} /><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">{cityWiseData.bilaspur.map(p => <PropertyCard key={p._id} item={p} />)}</div></div>
        )}
        {cityWiseData.raipur.length > 0 && (
          <div><SectionHeader title={`${catName} in Raipur`} /><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">{cityWiseData.raipur.map(p => <PropertyCard key={p._id} item={p} />)}</div></div>
        )}
        {cityWiseData.others.length > 0 && (
          <div><SectionHeader title="Other Locations" /><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">{cityWiseData.others.map(p => <PropertyCard key={p._id} item={p} />)}</div></div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#FAFAFA]">
      <div className="pt-12 pb-8 bg-white border-b border-gray-100 shadow-[0_4px_20px_-10px_rgba(0,0,0,0.05)]">
         <div className="max-w-7xl mx-auto px-6 md:px-10">
            <span className="text-blue-600 font-black text-xs tracking-[0.3em] uppercase mb-2 block">Real Estate</span>
            <h1 className="text-5xl md:text-7xl font-[1000] text-gray-900 tracking-tighter uppercase">
               {search || (category !== "All" ? category : "Explore")}
            </h1>
         </div>
      </div>

      <div className="max-w-7xl mx-auto p-6 md:p-10">
        {renderContent()}
        {properties.length === 0 && (
           <div className="text-center py-32 opacity-50"><p className="text-2xl font-black text-gray-400">NO PROPERTIES FOUND</p></div>
        )}
      </div>
    </div>
  );
}

export default function PropertiesPage() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <PropertiesContent />
    </Suspense>
  );
}